/// Attribute score normalization — v9 rank-aware per-face mapping.
///
/// Maps raw attribute scores (from `deriveAttributeScores`) to a user-facing
/// 5.0–10.0 range by blending:
///   - **global percentile** (calibration CDF → cross-user comparability)
///   - **within-face rank** (enforces ≥3.0 spread between top and bottom attr)
///
/// Quantile tables are generated by `test/calibration_test.dart` which runs
/// Monte Carlo through the real pipeline. Re-run after any weight/rule change.
library;

import 'package:face_reader/data/enums/attribute.dart';
import 'package:face_reader/data/enums/gender.dart';

